@page "/settings"
@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-3" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="mb-3">
            <label class="form-label">Mode</label>
            <select class="form-select" value="@currentTheme" @onchange="OnThemeChanged">
                @foreach (var t in Enum.GetValues<Theme>())
                {
                    <option value="@t">@t</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">Accent Color</label>
            <div class="d-flex align-items-center gap-2">
                <input type="color" class="form-control form-control-color"
                       value="@currentAccent" @onchange="OnAccentChanged" />
                <span class="text-muted">@currentAccent</span>
            </div>
        </div>

        <div class="alert alert-info mt-3 mb-0">
            Current: <strong>@currentTheme</strong> with accent
            <span style="color: @currentAccent;">■</span> @currentAccent
        </div>
    </div>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private Theme currentTheme;
    private string currentAccent = "#0d6efd";

    protected override void OnParametersSet()
    {
        if (Theme is not null)
        {
            currentTheme = Theme.Theme;
            currentAccent = Theme.AccentColor;
        }
    }

    private async Task OnThemeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<Theme>(e.Value?.ToString(), out var parsed))
        {
            currentTheme = parsed;
            await PushUpdate();
        }
    }

    private async Task OnAccentChanged(ChangeEventArgs e)
    {
        currentAccent = e.Value?.ToString() ?? currentAccent;
        await PushUpdate();
    }

    private async Task PushUpdate()
    {
        var updated = new ThemeInfo { Theme = currentTheme, AccentColor = currentAccent };
        await ThemeSource.NotifyChangedAsync(updated);
    }
}

